import { ShoppingCart, CartItem } from './shopping-cart.js';

function assertEqual(actual: any, expected: any, message: string): boolean {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    console.log(`✗ ${message}`);
    console.log(`  Expected: ${JSON.stringify(expected)}`);
    console.log(`  Actual: ${JSON.stringify(actual)}`);
    return false;
  }
  console.log(`✓ ${message}`);
  return true;
}

function runTests() {
  console.log('Running Shopping Cart tests...\n');
  let passed = 0;
  let failed = 0;

  // Test 1: Add item
  const cart1 = new ShoppingCart();
  cart1.addItem({ id: '1', name: 'Apple', price: 1.50, quantity: 2 });
  if (assertEqual(cart1.getItemCount(), 2, 'Add item - count correct')) passed++;
  else failed++;

  // Test 2: Add same item (quantity should increase)
  cart1.addItem({ id: '1', name: 'Apple', price: 1.50, quantity: 3 });
  if (assertEqual(cart1.getItemCount(), 5, 'Add same item - quantity increases')) passed++;
  else failed++;
  if (assertEqual(cart1.getItems().length, 1, 'Add same item - still 1 item type')) passed++;
  else failed++;

  // Test 3: Remove item
  const cart2 = new ShoppingCart();
  cart2.addItem({ id: '1', name: 'Apple', price: 1.00, quantity: 1 });
  cart2.addItem({ id: '2', name: 'Banana', price: 0.50, quantity: 1 });
  cart2.removeItem('1');
  if (assertEqual(cart2.getItems().length, 1, 'Remove item - reduces count')) passed++;
  else failed++;
  if (assertEqual(cart2.getItems()[0]?.id, '2', 'Remove item - correct item remains')) passed++;
  else failed++;

  // Test 4: Total calculation with floating point
  const cart3 = new ShoppingCart();
  cart3.addItem({ id: '1', name: 'Item', price: 0.1, quantity: 3 });
  const total = cart3.getTotal();
  // Should be 0.30, not 0.30000000000000004
  if (assertEqual(total, 0.3, 'Total calculation - handles floating point')) passed++;
  else failed++;

  console.log(`\nResults: ${passed} passed, ${failed} failed`);
  process.exit(failed > 0 ? 1 : 0);
}

runTests();
